import * as t from "io-ts";
import { BaseIntent } from "./baseIntent";
import { optionalString } from "../../../utils";
import { SuiFeeOptions } from "./suiFeeOptions";

export const SuiBuildOptions = t.intersection([
  BaseIntent,
  t.type({
    feeOptions: SuiFeeOptions,
    lockedAmount: optionalString,
  }),
]);

export type SuiBuildOptions = t.TypeOf<typeof SuiBuildOptions>;
